class Solution(object):
    def findKthSmallest(self, coins, k):
        """
        :type coins: List[int]
        :type k: int
        :rtype: int
        """
        from math import gcd
        from functools import reduce

        def count_amounts(limit, coins):
            """Count distinct amounts up to limit using inclusion-exclusion"""
            n = len(coins)
            count = 0

            # Iterate through all non-empty subsets
            for mask in range(1, 1 << n):
                # Get LCM of selected coins
                selected = []
                bits = bin(mask).count('1')

                for i in range(n):
                    if mask & (1 << i):
                        selected.append(coins[i])

                # Calculate LCM
                def lcm(a, b):
                    return a * b // gcd(a, b)

                lcm_val = reduce(lcm, selected)

                # Count multiples of lcm_val up to limit
                multiples = limit // lcm_val

                # Inclusion-exclusion: odd bits add, even bits subtract
                if bits % 2 == 1:
                    count += multiples
                else:
                    count -= multiples

            return count

        # Binary search for kth smallest amount
        left, right = 1, k * max(coins)

        while left < right:
            mid = (left + right) // 2
            count = count_amounts(mid, coins)

            if count < k:
                left = mid + 1
            else:
                right = mid

        return left
